mapper.update:
UPDATE project
SET name = #{name}, description = #{description}, version = #{version},
    page_count = #{pageCount}, status = #{status}, updated_at = #{updatedAt}
WHERE id = #{id}

mapper.select:
SELECT '项目创建' as action, name as detail, created_at as time, '成功' as status, '' as model
FROM project WHERE tenant_id = #{tenantId} AND deleted = 0
ORDER BY created_at DESC LIMIT #{limit}
